impl RingOp<W160> for Mul<W160> {
    type Operand = Limbs<3>;
    #[inline]
    fn apply(a: Limbs<3>, b: Limbs<3>) -> Limbs<3> {
        a.wrapping_mul(b).mask_high_bits(160)
    }
}

